import { writeOutput } from "./codegen";

const DOCS_URL =
  "https://developer.ticketmaster.com/products-and-docs/apis/discovery-api/v2/";
const PLACEHOLDER_VALUE = "CoffeeSafeLocalCoffeeSafeLocalCoffeeSafe";

function generateTypeScript(): string {
  const lines: string[] = [
    "// Auto-generated from Ticketmaster Discovery API docs.",
    `// Source: ${DOCS_URL}`,
    "// Regenerate: cd turbo && pnpm -F @vm0/firewalls-generator generate:ticketmaster",
    "//",
    "// DO NOT EDIT THIS FILE MANUALLY.",
    "",
    'import type { FirewallConfig } from "../firewall-types";',
    "",
    "export const ticketmasterFirewall = {",
    '  name: "ticketmaster",',
    '  description: "Ticketmaster Discovery API",',
    "  placeholders: {",
    `    TICKETMASTER_API_KEY: "${PLACEHOLDER_VALUE}",`,
    "  },",
    "  apis: [",
    "    {",
    '      base: "https://app.ticketmaster.com",',
    "      auth: {",
    "        query: {",
    '          apikey: "${{ secrets.TICKETMASTER_API_KEY }}",',
    "        },",
    "      },",
    "      permissions: [],",
    "    },",
    "  ],",
    "} as const satisfies FirewallConfig;",
    "",
  ];

  return lines.join("\n");
}

export async function generate(): Promise<void> {
  console.error("Generating Ticketmaster firewall config...");
  const ts = generateTypeScript();
  writeOutput("ticketmaster", ts, import.meta.dirname);
}
